use loom::sync::{Arc, Mutex};
use loom::thread;

#[test]
fn loom_continuation_timeout_concurrent_access() {
    loom::model(|| {
        let conn = Arc::new(Mutex::new(ContinuationState::new()));

        let conn1 = Arc::clone(&conn);
        let t1 = thread::spawn(move || {
            let mut state = conn1.lock().unwrap();
            state.start_continuation(1);
        });

        let conn2 = Arc::clone(&conn);
        let t2 = thread::spawn(move || {
            let mut state = conn2.lock().unwrap();
            state.check_timeout();
        });

        let conn3 = Arc::clone(&conn);
        let t3 = thread::spawn(move || {
            let mut state = conn3.lock().unwrap();
            state.complete_continuation(1);
        });

        t1.join().unwrap();
        t2.join().unwrap();
        t3.join().unwrap();

        // State should be consistent regardless of ordering
        let state = conn.lock().unwrap();
        assert!(state.is_consistent());
    });
}

#[test]
fn loom_continuation_timeout_vs_completion_race() {
    loom::model(|| {
        let state = Arc::new(ContinuationState::new());

        // Thread 1: Timeout fires
        let s1 = Arc::clone(&state);
        let t1 = thread::spawn(move || {
            s1.fire_timeout()
        });

        // Thread 2: Completion arrives
        let s2 = Arc::clone(&state);
        let t2 = thread::spawn(move || {
            s2.complete(b"final header block")
        });

        let timeout_result = t1.join().unwrap();
        let complete_result = t2.join().unwrap();

        // Exactly one should succeed
        assert_ne!(timeout_result.is_ok(), complete_result.is_ok());
    });
}
```

