    let headers = encode_headers_frame(1, &[
        (":method", "GET"),
        (":path", "/test"),
    ], false /* no END_HEADERS */);
    stream.write_all(&headers).await?;

    // Wait for timeout (server configured with 5s default)
    tokio::time::sleep(Duration::from_secs(6)).await;

    // Server should have closed connection or sent GOAWAY
    let mut buf = [0u8; 1024];
    match stream.read(&mut buf).await {
        Ok(0) => (), // Connection closed - expected
        Ok(n) => {
            let frame = parse_frame(&buf[..n]);
            assert!(matches!(frame, Frame::GoAway { .. }));
        }
        Err(e) => assert!(e.kind() == std::io::ErrorKind::ConnectionReset),
    }
}
