## Two-Phase Write (Cancel-Safe)

For truly cancel-safe writes, use WritePermit pattern:

```rust
/// Reserve write capacity
pub struct WritePermit<'a, W: AsyncWrite + ?Sized> {
    writer: &'a mut W,
    data: Vec<u8>,
}

impl<'a, W: AsyncWrite + Unpin + ?Sized> WritePermit<'a, W> {
    /// Reserve space for writing
    pub async fn reserve(writer: &'a mut W, len: usize) -> io::Result<Self> {
        Ok(WritePermit {
            writer,
            data: Vec::with_capacity(len),
        })
    }

    /// Stage data for writing
    pub fn stage(&mut self, data: &[u8]) {
        self.data.extend_from_slice(data);
    }

    /// Commit the write (consumes permit)
    pub async fn commit(mut self) -> io::Result<()> {
        self.writer.write_all(&self.data).await
    }
}

impl<W: AsyncWrite + ?Sized> Drop for WritePermit<'_, W> {
    fn drop(&mut self) {
        // Data discarded if not committed - explicit abort
    }
}
```

## Future Types

```rust
/// Future for write_all
pub struct WriteAll<'a, W: ?Sized> {
    writer: &'a mut W,
    buf: &'a [u8],
    pos: usize,
}

impl<W: AsyncWrite + Unpin + ?Sized> Future for WriteAll<'_, W> {
    type Output = io::Result<()>;

    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let this = self.get_mut();
        while this.pos < this.buf.len() {
            let n = ready!(Pin::new(&mut *this.writer)
                .poll_write(cx, &this.buf[this.pos..]))?;

            if n == 0 {
                return Poll::Ready(Err(io::Error::from(io::ErrorKind::WriteZero)));
            }
            this.pos += n;
        }
        Poll::Ready(Ok(()))
    }
}
```

